beforeSaveCustomScript:
// ===== TROVA CAP =====
$capRecordId = record\findOne('CAP', null, null, 'name=', prospect.addressPostalCode);

if ($capRecordId) {
    cAPId = $capRecordId;
}

// ===== RECUPERO DATI CAP DIRETTI =====
$capName = record\attribute('CAP', $capRecordId, 'name');
$capCodice = record\attribute('CAP', $capRecordId, 'codiceCAP');
$capDesc = record\attribute('CAP', $capRecordId, 'description');

// ===== BLOCCO CAP =====
$capBlock = null;

if ($capName) {

    $capBlock = $capName;

    if ($capCodice) {
        $capBlock = string\concatenate($capBlock, ' - ', $capCodice);
    }

    if ($capDesc) {
        $capBlock = string\concatenate($capBlock, ' (', $capDesc, ')');
    }
}

// ===== BLOCCO PROSPECT =====
$prospectBlock = ifThenElse(
    prospectName,
    prospectName,
    '(APPUNTAMENTO SENZA PROSPECT)'
);

// ===== BLOCCO BRAND + CATEGORIA PRODOTTO (naming) =====
$brandLabel = ifThenElse(
    azienda,
    azienda,
    productBrandName
);

$categoriaLabel = ifThenElse(
    productCategoryName,
    productCategoryName,
    lineaProdotto
);

$extraBlock = null;

if ($brandLabel || $categoriaLabel) {

    if ($brandLabel && $categoriaLabel) {
        $extraBlock = string\concatenate(' (', $brandLabel, ' - ', $categoriaLabel, ')');
    } else {
        $extraBlock = string\concatenate(' (', ifThenElse($brandLabel, $brandLabel, $categoriaLabel), ')');
    }
}

// ===== BUILD FINALE =====
name = string\concatenate(
    ifThenElse($capBlock, string\concatenate($capBlock, ' - '), ''),
    $prospectBlock,
    ifThenElse($extraBlock, $extraBlock, '')
);
